一、請依據下列 C++程式碼執行後，試問輸出結果為何？（25 分）
#include <stdio.h>
#include <stdlib.h>
int ABC(int n) {
if (n <= 1)
return 1;
else
return n * ABC(n - 1);
}
int main() {
int i, sum = 0;
for (i = 0; i < 8; i = i + 1) {
sum += ABC(i);
printf("%d\n", sum);
}
system("pause");
